package be.schaubroeck.lpb.rkm.rekenmotor.feestdagen;

import be.schaubroeck.lpb.rkm.feestdagen.VergoedingFeestDagResultaat;
import be.schaubroeck.lpb.rkm.feestdagen.VergoedingFeestdagService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManagerImp;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Instelling;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enums.al.instelling.ToepassingSleutel;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExtensieGroepType;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.Hoedanigheid;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.model.AardKodeExtensieGroepBO;
import be.schaubroeck.lpb.tools.service.BetaaldeFeestdagDefinitieGLService;
import be.schaubroeck.lpb.tools.service.ConstantService;
import be.schaubroeck.lpb.tools.service.InstellingService;
import be.schaubroeck.lpb.tools.service.common.AardKodeExtensieGroepBOService;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import be.schaubroeck.temporal.interval.Month;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.function.Predicate;
import java.util.stream.Collectors;

public class VergoedingFeestdagServiceImp implements VergoedingFeestdagService {

    @Autowired
    private BetaaldeFeestdagDefinitieGLService betaaldeFeestdagDefinitieGLService;
    @Autowired
    private AardKodeExtensieFacade aardKodeExtensieFacade;
    @Autowired
    private ConstantService constantService;
    @Autowired
    private InstellingService instellingService;
    @Autowired
    private AardKodeExtensieGroepBOService aardKodeExtensieGroepBOService;
    @Autowired
    private BerekenVergoedingFeestDag berekenVergoedingFeestDag;

    private static final int VERGOEDING_FEESTDAG_CODE_VASTBENOEMDE = 434;
    private static final int VERGOEDING_FEESTDAGCODE_CONTRACTUELEN = 834;
    private static final int VERGOEDING_FEESTDAG_EXTENSIE = 251;

    private static final Predicate<Opdracht> IS_CONTRACTUEEL =
            x -> x.getHoedanigheid() == Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN || x.getHoedanigheid() == Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN;
    private static final Predicate<Opdracht> IS_VASTBENOEMD = x -> x.getHoedanigheid() == Hoedanigheid.VASTBENOEMDEN;

    @Override
    @InitializeAdmin
    public List<VergoedingFeestDagResultaat> rekenVergoedingFeestdag(Admin admin, List<Opdracht> opdrachten, LocalDate referteDatum) {
        List<VergoedingFeestDagResultaat> resultaten = new ArrayList<>();
        VergoedingFeestDagData basisData = bepaalVergoedingFeestDagData(admin, referteDatum);
        List<Opdracht> contractuelen = opdrachten.stream().filter(IS_CONTRACTUEEL).collect(Collectors.toList());
        List<Opdracht> vastbenoemden = opdrachten.stream().filter(IS_VASTBENOEMD).collect(Collectors.toList());
        if (basisData.isVanToepassing(Hoedanigheid.VASTBENOEMDEN)) {
            resultaten.addAll(berekenVergoedingFeestDag.rekenVergoeding(admin, basisData, vastbenoemden, referteDatum));
        }
        if (basisData.isVanToepassing(Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN)) {
            resultaten.addAll(berekenVergoedingFeestDag.rekenVergoeding(admin, basisData, contractuelen, referteDatum));
        }
        return resultaten;
    }

    public VergoedingFeestDagData bepaalVergoedingFeestDagData(Admin admin, LocalDate datum) {
        ConstantManager constantManager = new ConstantManagerImp(admin, constantService);
        boolean actief = constantManager.getByCodeDatum(Konstanten.KST_SUPPLEMENTEN_FEESTDAGEN_TOEPASSING.getCode(), datum).getBoolean();
        Set<Integer> werkgeverIds =
                new HashSet<>(instellingService.getIntegerListByAdminToepassingSleutel(admin, ToepassingSleutel.REKENMOTOR_SUPPLEMENTEN_FEESTDAGEN_WERKGEVERS));
        int aantalFeestdagenContractuelen = betaaldeFeestdagDefinitieGLService.aantalWettelijkeFeestdagenInPeriode(new Month(datum.minusMonths(1)));
        int aantalFeestdagenVastbenoemden = betaaldeFeestdagDefinitieGLService.aantalWettelijkeFeestdagenInPeriode(new Month(datum.minusMonths(2)));
        AardKodeExtensie loonCodeVastbenoemden =
                aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(AkeTijdperk.DMFAPPL, AardKodeExt.S_KODE_EXT, VERGOEDING_FEESTDAG_CODE_VASTBENOEMDE,
                        VERGOEDING_FEESTDAG_EXTENSIE);
        AardKodeExtensie loonCodeContractuelen =
                aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(AkeTijdperk.DMFAPPL, AardKodeExt.S_KODE_EXT, VERGOEDING_FEESTDAGCODE_CONTRACTUELEN,
                        VERGOEDING_FEESTDAG_EXTENSIE);
        Instelling statutairInstelling = instellingService.getByAdminToepassingSleutel(admin, ToepassingSleutel.REKENMOTOR_SUPPLEMENTEN_FEESTDAGEN_STATUTAIREN);
        loonCodeVastbenoemden = getLoonCodeVastbenoemden(loonCodeVastbenoemden, statutairInstelling);
        AardKodeExtensieGroepBO supplementenGroep = aardKodeExtensieGroepBOService.getByDatum(admin, AardKodeExtensieGroepType.SUPPLEMENTEN_FEESTDAGEN, datum);
        Set<Integer> akeIdsSupplementenFeestDagen = new HashSet<>();
        if (supplementenGroep != null) {
            akeIdsSupplementenFeestDagen = supplementenGroep.getItems().stream().map(x -> x.getAardKodeExtensie().getId()).collect(Collectors.toSet());
        }
        return new VergoedingFeestDagData(actief, aantalFeestdagenContractuelen, aantalFeestdagenVastbenoemden, loonCodeVastbenoemden, loonCodeContractuelen,
                werkgeverIds, akeIdsSupplementenFeestDagen);
    }

    private AardKodeExtensie getLoonCodeVastbenoemden(AardKodeExtensie loonCodeVastbenoemden, Instelling statutairInstelling) {
        if (statutairInstelling != null) {
            int waarde = Integer.parseInt(statutairInstelling.getWaarde());
            return aardKodeExtensieFacade.getById(waarde);
        }
        return loonCodeVastbenoemden;
    }
}
